(function () { "use strict"; var SPLASH_MIN_MS = 1000; var SPLASH_MAX_MS = 2000; function isStandalone() { return ( window.matchMedia("(display-mode: standalone)").matches || window.navigator.standalone === true ); } function hideSplash() { var splash = document.getElementById("mobile-splash"); if (!splash) return; splash.classList.add("mobile-splash--hide"); setTimeout(function () { splash.remove(); }, 420); } document.addEventListener("DOMContentLoaded", function () { var splash = document.getElementById("mobile-splash"); if (!splash) return; if (!isStandalone()) { splash.remove(); return; } var started = Date.now(); function finish() { var elapsed = Date.now() - started; var wait = Math.max(0, SPLASH_MIN_MS - elapsed); wait = Math.min(wait, SPLASH_MAX_MS); setTimeout(hideSplash, wait); } if (document.readyState === "complete") { finish(); } else { window.addEventListener("load", finish, { once: true }); setTimeout(finish, SPLASH_MAX_MS); } }); })();